            var result = await _executor.ExecuteAsync(request.Query);
            return Ok(result);
        }
    }

    public class Query
    {
        // VULNERABLE: Direct SQL concatenation in resolver
        public async Task<User> GetUser(string id, [Service] SqlConnection connection)
        {
