**Attack Payload - SQL Injection via GraphQL**:
```graphql
query {
  getUser(id: "' OR '1'='1' UNION SELECT id, email, password_hash FROM admin_users--") {
    id
    email
  }
}
```

**Attack Payload - Nested Query DoS (Query Bomb)**:
```graphql
query MaliciousQuery {
  users {
    friends {
      friends {
        friends {
          friends {
            friends {
              id
              email
            }
          }
        }
      }
    }
  }
}
```

**Attack Payload - Introspection Abuse**:
```graphql
query IntrospectionQuery {
  __schema {
    types {
      name
      fields {
        name
        type {
          name
        }
      }
    }
  }
}
```

**Why This Is Dangerous**:
- Direct string concatenation in resolvers enables SQL injection through GraphQL variables
- No query depth limiting allows attackers to craft exponentially expensive queries
- Introspection enabled in production reveals entire schema structure to attackers
- Missing authorization allows any authenticated user to access all data
- No query complexity analysis enables resource exhaustion attacks

**SECURE VERSION**:

```csharp
using HotChocolate;
using HotChocolate.AspNetCore;
using HotChocolate.Authorization;
using HotChocolate.Execution;
using HotChocolate.Execution.Options;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Data.SqlClient;
using System.Security.Claims;

namespace SecureApi
{
    public static class GraphQLConfiguration
    {
        public static IServiceCollection AddSecureGraphQL(this IServiceCollection services)
        {
            services
                .AddGraphQLServer()
                .AddQueryType<Query>()
                .AddAuthorization()
                // SECURITY: Disable introspection in production
                .ModifyRequestOptions(opt => 
                {
                    opt.IncludeExceptionDetails = false;
                })
                // SECURITY: Limit query depth to prevent nested attacks
                .AddMaxExecutionDepthRule(5)
                // SECURITY: Limit query complexity
                .SetMaxAllowedValidationErrors(10)
                .AddProjections()
                .AddFiltering()
                .AddSorting();

            return services;
        }
    }

    public class Query
    {
        // SECURE: Parameterized query with authorization
        [Authorize(Policy = "ReadUsers")]
        public async Task<User?> GetUser(
            string id,
            [Service] IDbContextFactory<AppDbContext> contextFactory,
            [Service] ILogger<Query> logger,
            ClaimsPrincipal claimsPrincipal)
        {
            // SECURITY: Input validation
            if (!Guid.TryParse(id, out var userId))
            {
                logger.LogWarning("Invalid user ID format: {AttemptedId} by {User}", 
                    id, claimsPrincipal.Identity?.Name);
                return null;
            }

            await using var context = await contextFactory.CreateDbContextAsync();

            // SECURE: Entity Framework uses parameterized queries
            var user = await context.Users
                .Where(u => u.Id == userId)
                .Select(u => new User 
                { 
                    Id = u.Id.ToString(), 
                    Email = u.Email 
                    // SECURITY: Never expose PasswordHash
                })
                .FirstOrDefaultAsync();

            logger.LogInformation("User {UserId} accessed by {RequestingUser}", 
                id, claimsPrincipal.Identity?.Name);

            return user;
        }

        // SECURE: Authorization attribute ensures only admins can list all users
        [Authorize(Roles = new[] { "Admin" })]
        public async Task<List<User>> GetAllUsers(
            [Service] IDbContextFactory<AppDbContext> contextFactory,
            [Service] ILogger<Query> logger,
            ClaimsPrincipal claimsPrincipal)
        {
            await using var context = await contextFactory.CreateDbContextAsync();

            logger.LogInformation("All users listing accessed by admin: {Admin}", 
                claimsPrincipal.Identity?.Name);

            return await context.Users
                .Select(u => new User { Id = u.Id.ToString(), Email = u.Email })
                .Take(100) // SECURITY: Limit results
                .ToListAsync();
        }
    }

    public class User
    {
        public string Id { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        // PasswordHash intentionally excluded from GraphQL type
    }
}
```

**Key Security Controls**:
- **Parameterized Queries**: Entity Framework automatically parameterizes all database queries, preventing SQL injection
- **Query Depth Limiting**: `AddMaxExecutionDepthRule(5)` prevents deeply nested query attacks that cause DoS
- **Authorization Attributes**: `[Authorize]` decorators enforce role-based access control on resolvers
- **Input Validation**: GUID parsing ensures only valid identifiers are accepted
- **Audit Logging**: All data access is logged with user identity for forensic analysis
- **Sensitive Data Filtering**: PasswordHash is never exposed in the GraphQL schema

Mutations require additional protections including CSRF prevention, idempotency handling, and strict input validation. Batched queries can amplify attacks, so you need comprehensive rate limiting and cost analysis.

**PRODUCTION PATTERN**:

```csharp
using HotChocolate;
using HotChocolate.AspNetCore;
using HotChocolate.Authorization;
using HotChocolate.Execution;
using HotChocolate.Execution.Configuration;
using HotChocolate.Execution.Options;
using HotChocolate.Types;
using Microsoft.AspNetCore.RateLimiting;
using Microsoft.Extensions.Caching.Distributed;
using System.Security.Claims;
using System.Threading.RateLimiting;

namespace SecureApi.Production
{
    // Program.cs configuration
    public static class SecureGraphQLStartup
    {
        public static IServiceCollection AddProductionGraphQL(
            this IServiceCollection services, 
            IConfiguration configuration)
        {
            var isProduction = configuration.GetValue<bool>("IsProduction");

            services
                .AddGraphQLServer()
                .AddQueryType<SecureQuery>()
                .AddMutationType<SecureMutation>()
                .AddAuthorization()

                // SECURITY: Disable introspection in production
                .AddIntrospectionAllowedRule()
                .ModifyRequestOptions(opt =>
                {
                    opt.IncludeExceptionDetails = !isProduction;
                    opt.ExecutionTimeout = TimeSpan.FromSeconds(30);
                })

                // SECURITY: Query complexity and depth limits
                .AddMaxExecutionDepthRule(6)
                .SetMaxAllowedValidationErrors(5)

                // SECURITY: Persisted queries only in production
                .UsePersistedQueryPipeline()
                .AddReadOnlyFileSystemQueryStorage("./persisted-queries")

                // SECURITY: Cost-based query analysis
                .UseAutomaticPersistedQueryPipeline()
                .ConfigureSchema(sb =>
                {
                    if (isProduction)
                    {
                        sb.AddDirectiveType<CostDirectiveType>();
                    }
                })

                .AddProjections()
                .AddFiltering()
                .AddSorting()
                .AddErrorFilter<ProductionErrorFilter>();

            // SECURITY: Rate limiting
            services.AddRateLimiter(options =>
            {
                options.GlobalLimiter = PartitionedRateLimiter.Create<HttpContext, string>(context =>
                {
                    var userId = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value 
                        ?? context.Connection.RemoteIpAddress?.ToString() 
                        ?? "anonymous";

                    return RateLimitPartition.GetTokenBucketLimiter(userId, _ => new TokenBucketRateLimiterOptions
                    {
                        TokenLimit = 100,
                        ReplenishmentPeriod = TimeSpan.FromMinutes(1),
                        TokensPerPeriod = 50,
                        QueueProcessingOrder = QueueProcessingOrder.OldestFirst,
                        QueueLimit = 5
                    });
                });

                options.OnRejected = async (context, token) =>
                {
                    var logger = context.HttpContext.RequestServices
                        .GetRequiredService<ILogger<Program>>();

                    logger.LogWarning("Rate limit exceeded for {IP}", 
                        context.HttpContext.Connection.RemoteIpAddress);

                    context.HttpContext.Response.StatusCode = 429;
                    await context.HttpContext.Response.WriteAsJsonAsync(new
                    {
                        errors = new[] { new { message = "Too many requests" } }
                    }, token);
                };
            });

            return services;
        }
    }

    // Custom cost directive for query complexity analysis
    public class CostDirectiveType : DirectiveType
    {
        protected override void Configure(IDirectiveTypeDescriptor descriptor)
        {
            descriptor.Name("cost");
            descriptor.Location(DirectiveLocation.FieldDefinition);
            descriptor.Argument("complexity").Type<NonNullType<IntType>>();
        }
    }

    // Secure mutation with CSRF protection and idempotency
    public class SecureMutation
    {
        [Authorize]
        [GraphQLDescription("Creates a new user account")]
        public async Task<CreateUserPayload> CreateUser(
            CreateUserInput input,
            [Service] IDbContextFactory<AppDbContext> contextFactory,
            [Service] ILogger<SecureMutation> logger,
            [Service] IDistributedCache cache,
            [Service] ISecurityAuditService auditService,
            ClaimsPrincipal claimsPrincipal,
            CancellationToken cancellationToken)
        {
            var requestingUser = claimsPrincipal.FindFirst(ClaimTypes.NameIdentifier)?.Value;

            // SECURITY: Idempotency check to prevent duplicate operations
            if (!string.IsNullOrEmpty(input.IdempotencyKey))
            {
                var existingResult = await cache.GetStringAsync(
                    $"idempotency:{input.IdempotencyKey}", cancellationToken);

                if (existingResult != null)
                {
                    logger.LogInformation("Idempotent request detected: {Key}", 
                        input.IdempotencyKey);
                    return System.Text.Json.JsonSerializer
                        .Deserialize<CreateUserPayload>(existingResult)!;
                }
            }

            // SECURITY: Comprehensive input validation
            var validationErrors = new List<UserError>();

            if (string.IsNullOrWhiteSpace(input.Email) || 
                !IsValidEmail(input.Email))
            {
                validationErrors.Add(new UserError("INVALID_EMAIL", 
                    "A valid email address is required"));
            }

            if (string.IsNullOrWhiteSpace(input.Password) || 
                input.Password.Length < 12)
            {
                validationErrors.Add(new UserError("WEAK_PASSWORD", 
                    "Password must be at least 12 characters"));
            }

            if (validationErrors.Any())
            {
                return new CreateUserPayload(null, validationErrors);
            }

            await using var context = await contextFactory.CreateDbContextAsync(cancellationToken);

            // SECURITY: Check for existing user (prevent enumeration via timing)
            var existingUser = await context.Users
                .AnyAsync(u => u.NormalizedEmail == input.Email.ToUpperInvariant(), 
                    cancellationToken);

            if (existingUser)
            {
                // SECURITY: Generic error to prevent email enumeration
                await Task.Delay(Random.Shared.Next(50, 150), cancellationToken);
                validationErrors.Add(new UserError("REGISTRATION_FAILED", 
                    "Unable to complete registration"));
                return new CreateUserPayload(null, validationErrors);
            }

            var newUser = new UserEntity
            {
                Id = Guid.NewGuid(),
                Email = input.Email,
                NormalizedEmail = input.Email.ToUpperInvariant(),
                PasswordHash = BCrypt.Net.BCrypt.HashPassword(input.Password, 12),
                CreatedAt = DateTime.UtcNow,
                CreatedBy = requestingUser
            };

            context.Users.Add(newUser);
            await context.SaveChangesAsync(cancellationToken);

            // SECURITY: Audit logging
            await auditService.LogAsync(new AuditEvent
            {
                Action = "USER_CREATED",
                ActorId = requestingUser,
                TargetId = newUser.Id.ToString(),
                Timestamp = DateTime.UtcNow,
                IpAddress = GetClientIp(claimsPrincipal),
                Details = new { Email = MaskEmail(input.Email) }
            }, cancellationToken);

            var payload = new CreateUserPayload(
                new User { Id = newUser.Id.ToString(), Email = newUser.Email },
                new List<UserError>());

            // SECURITY: Cache idempotency result
            if (!string.IsNullOrEmpty(input.IdempotencyKey))
            {
                await cache.SetStringAsync(
                    $"idempotency:{input.IdempotencyKey}",
                    System.Text.Json.JsonSerializer.Serialize(payload),
                    new DistributedCacheEntryOptions
                    {
                        AbsoluteExpirationRelativeToNow = TimeSpan.FromHours(24)
                    },
                    cancellationToken);
            }

            logger.LogInformation("User created: {UserId} by {RequestingUser}", 
                newUser.Id, requestingUser);

            return payload;
        }

        private static bool IsValidEmail(string email)
        {
            try
            {
                var addr = new System.Net.Mail.MailAddress(email);
                return addr.Address == email && 
                       email.Length <= 254 && 
                       !email.Contains("..");
            }
            catch { return false; }
        }

        private static string MaskEmail(string email)
        {
            var parts = email.Split('@');
            if (parts.Length != 2) return "***";
            var local = parts[0].Length > 2 
                ? parts[0][0] + "***" + parts[0][^1] 
                : "***";
            return $"{local}@{parts[1]}";
        }

        private static string? GetClientIp(ClaimsPrincipal principal) =>
            principal.FindFirst("client_ip")?.Value;
    }

    // Production error filter - never expose internal errors
    public class ProductionErrorFilter : IErrorFilter
    {
        private readonly ILogger<ProductionErrorFilter> _logger;
        private readonly IHostEnvironment _environment;

        public ProductionErrorFilter(
            ILogger<ProductionErrorFilter> logger,
            IHostEnvironment environment)
        {
            _logger = logger;
            _environment = environment;
        }

        public IError OnError(IError error)
        {
            _logger.LogError(error.Exception, "GraphQL Error: {Message}", error.Message);

            if (_environment.IsProduction())
            {
                // SECURITY: Never expose stack traces or internal messages
                return ErrorBuilder.New()
                    .SetMessage("An error occurred processing your request")
                    .SetCode("INTERNAL_ERROR")
                    .Build();
            }

            return error;
        }
    }

    // Input/Output types with validation
    public record CreateUserInput(
        string Email,
        string Password,
        string? IdempotencyKey);

    public record CreateUserPayload(
        User? User,
        IReadOnlyList<UserError> Errors);

    public record UserError(string Code, string Message);

    public class User
    {
        public string Id { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
    }

    public interface ISecurityAuditService
    {
        Task LogAsync(AuditEvent evt, CancellationToken ct);
    }

    public class AuditEvent
    {
        public string Action { get; set; } = string.Empty;
        public string? ActorId { get; set; }
        public string? TargetId { get; set; }
        public DateTime Timestamp { get; set; }
        public string? IpAddress { get; set; }
        public object? Details { get; set; }
    }
}
```

**Defense in Depth Layers**:

1. **Query Complexity Analysis**: Assign costs to fields and reject queries exceeding thresholds
