public class GraphQLAnomalyDetectionMiddleware
{
    public async Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        var operationName = context.Request.Headers["X-GraphQL-Operation"].ToString();
        var clientId = context.User.FindFirst("client_id")?.Value;

        // Track unusual patterns
        if (await _anomalyDetector.IsAnomalousAsync(clientId, operationName))
        {
