**Additional Protections**:
- **Batching Limits**: Restrict the number of operations in a single request to prevent batch attacks (`services.AddGraphQLServer().ModifyRequestOptions(o => o.MaximumAllowedOperations = 5)`)
- **Field-Level Authorization**: Use `[Authorize]` on individual fields to implement fine-grained access control based on user roles/permissions
- **Query Allowlisting**: In high-security environments, only permit queries that have been explicitly approved and stored as persisted queries
- **Response Size Limits**: Cap maximum response payload size to prevent data exfiltration and resource exhaustion
- **Correlation IDs**: Include unique request IDs in all logs and responses for forensic tracing across distributed systems
- **Security Headers**: Return `X-Content-Type-Options: nosniff`, `X-Frame-Options: DENY`, and CSP headers on all GraphQL responses

LDAP filter injection is a critical vulnerability that occurs when user input is directly concatenated into LDAP queries. This can allow attackers to bypass authentication, extract sensitive directory information, or enumerate all users.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/go-ldap/ldap/v3"
)

type LDAPAuth struct {
	conn   *ldap.Conn
	baseDN string
}

func (auth *LDAPAuth) FindUser(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("username")

	// VULNERABLE: Direct string concatenation in LDAP filter
	filter := fmt.Sprintf("(&(objectClass=user)(sAMAccountName=%s))", username)

	searchRequest := ldap.NewSearchRequest(
		auth.baseDN,
		ldap.ScopeWholeSubtree,
		ldap.NeverDerefAliases,
		0, 0, false,
		filter,
		[]string{"dn", "cn", "mail", "memberOf"},
		nil,
	)

	result, err := auth.conn.Search(searchRequest)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	for _, entry := range result.Entries {
		fmt.Fprintf(w, "Found: %s\n", entry.DN)
	}
}
```

**Attack Payload**:
```text
*)(objectClass=*
```

This transforms the filter into `(&(objectClass=user)(sAMAccountName=*)(objectClass=*))` which matches ALL users in the directory.

More dangerous payload:
```text
admin)(|(password=*)
```

This attempts to extract password hashes by creating: `(&(objectClass=user)(sAMAccountName=admin)(|(password=*)))`

**Why This Is Dangerous**:
- Attackers can enumerate all users in Active Directory
- Authentication bypass by matching any user account
- Extraction of sensitive attributes like password hashes or security questions
- Potential for privilege escalation by finding admin accounts

**SECURE VERSION**:

```go
package main

import (
	"fmt"
	"log"
	"net/http"
	"regexp"
	"strings"

	"github.com/go-ldap/ldap/v3"
)

type LDAPAuth struct {
	conn   *ldap.Conn
	baseDN string
}

// escapeLDAPFilter escapes special LDAP filter characters per RFC 4515
func escapeLDAPFilter(input string) string {
	// Characters that must be escaped: * ( ) \ NUL
	replacer := strings.NewReplacer(
		"\\", "\\5c",
		"*", "\\2a",
		"(", "\\28",
		")", "\\29",
		"\x00", "\\00",
	)
	return replacer.Replace(input)
}

// validateUsername ensures username matches expected format
func validateUsername(username string) bool {
	// Only allow alphanumeric, dots, underscores, hyphens
	validPattern := regexp.MustCompile(`^[a-zA-Z0-9._-]{1,64}$`)
	return validPattern.MatchString(username)
}

func (auth *LDAPAuth) FindUser(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("username")

	// Input validation - reject invalid usernames early
	if !validateUsername(username) {
		log.Printf("Invalid username format attempted: %s from %s", username, r.RemoteAddr)
		http.Error(w, "Invalid username format", http.StatusBadRequest)
		return
	}

	// SECURE: Escape special LDAP filter characters
	safeUsername := escapeLDAPFilter(username)
	filter := fmt.Sprintf("(&(objectClass=user)(sAMAccountName=%s))", safeUsername)

	searchRequest := ldap.NewSearchRequest(
		auth.baseDN,
		ldap.ScopeWholeSubtree,
		ldap.NeverDerefAliases,
		1, // Limit to 1 result to prevent enumeration
		10, // 10 second timeout
		false,
		filter,
		[]string{"dn", "cn", "mail"}, // Only return necessary attributes
		nil,
	)

	result, err := auth.conn.Search(searchRequest)
	if err != nil {
		log.Printf("LDAP search error: %v", err)
		http.Error(w, "Search failed", http.StatusInternalServerError)
		return
	}

	if len(result.Entries) == 1 {
		fmt.Fprintf(w, "Found: %s\n", result.Entries[0].GetAttributeValue("cn"))
	} else {
		http.Error(w, "User not found", http.StatusNotFound)
	}
}
```

**Key Security Controls**:
- **RFC 4515 Escaping**: Special characters `* ( ) \ NUL` are escaped to their hex representations, preventing filter manipulation
- **Input Validation**: Whitelist regex ensures only valid username characters are accepted
- **Result Limiting**: `SizeLimit: 1` prevents bulk enumeration attacks
- **Attribute Restriction**: Only necessary attributes returned, reducing data exposure

Building dynamic LDAP filters safely requires a structured approach with a filter builder pattern that enforces escaping at every injection point.

**PRODUCTION PATTERN**:

```go
package ldapsearch

import (
	"context"
	"fmt"
	"log"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/go-ldap/ldap/v3"
)

// LDAPFilterBuilder safely constructs LDAP filters
type LDAPFilterBuilder struct {
	conditions []string
	mu         sync.Mutex
}

// LDAPSearchService handles secure LDAP operations
type LDAPSearchService struct {
	pool       chan *ldap.Conn
	baseDN     string
	logger     *log.Logger
	maxResults int
	timeout    time.Duration
}

// NewLDAPSearchService creates a production-ready LDAP service
func NewLDAPSearchService(baseDN string, poolSize int) *LDAPSearchService {
	return &LDAPSearchService{
		pool:       make(chan *ldap.Conn, poolSize),
		baseDN:     baseDN,
		logger:     log.Default(),
		maxResults: 100,
		timeout:    30 * time.Second,
	}
}

// EscapeLDAPValue escapes values for safe LDAP filter inclusion per RFC 4515
func EscapeLDAPValue(value string) string {
	var builder strings.Builder
	for _, char := range value {
		switch char {
		case '\\':
			builder.WriteString("\\5c")
		case '*':
			builder.WriteString("\\2a")
		case '(':
			builder.WriteString("\\28")
		case ')':
			builder.WriteString("\\29")
		case '\x00':
			builder.WriteString("\\00")
		default:
			builder.WriteRune(char)
		}
	}
	return builder.String()
}

// ValidateAttributeName ensures attribute names are safe
func ValidateAttributeName(attr string) bool {
	// LDAP attribute names: alphanumeric and hyphens only
	validAttr := regexp.MustCompile(`^[a-zA-Z][a-zA-Z0-9-]{0,63}$`)
	return validAttr.MatchString(attr)
}

// NewFilterBuilder creates a new safe filter builder
func NewFilterBuilder() *LDAPFilterBuilder {
	return &LDAPFilterBuilder{
		conditions: make([]string, 0),
	}
}

// AddEquals adds an equality condition with safe escaping
func (fb *LDAPFilterBuilder) AddEquals(attribute, value string) error {
	fb.mu.Lock()
	defer fb.mu.Unlock()

	if !ValidateAttributeName(attribute) {
		return fmt.Errorf("invalid attribute name: %s", attribute)
	}

	// Always escape the value
	safeValue := EscapeLDAPValue(value)
	fb.conditions = append(fb.conditions, fmt.Sprintf("(%s=%s)", attribute, safeValue))
	return nil
}

// AddPresence adds a presence check (attribute exists)
func (fb *LDAPFilterBuilder) AddPresence(attribute string) error {
	fb.mu.Lock()
	defer fb.mu.Unlock()

	if !ValidateAttributeName(attribute) {
		return fmt.Errorf("invalid attribute name: %s", attribute)
	}

	fb.conditions = append(fb.conditions, fmt.Sprintf("(%s=*)", attribute))
	return nil
}

// AddSubstring adds a safe substring search
func (fb *LDAPFilterBuilder) AddSubstring(attribute, prefix, any, suffix string) error {
	fb.mu.Lock()
	defer fb.mu.Unlock()

	if !ValidateAttributeName(attribute) {
		return fmt.Errorf("invalid attribute name: %s", attribute)
	}

	// Escape all parts - the * here is a filter wildcard, not user input
	var parts []string
	if prefix != "" {
		parts = append(parts, EscapeLDAPValue(prefix))
	}
	parts = append(parts, "*")
	if any != "" {
		parts = append(parts, EscapeLDAPValue(any), "*")
	}
	if suffix != "" {
		parts = append(parts, EscapeLDAPValue(suffix))
	}

	fb.conditions = append(fb.conditions, fmt.Sprintf("(%s=%s)", attribute, strings.Join(parts, "")))
	return nil
}

// BuildAND combines all conditions with AND
func (fb *LDAPFilterBuilder) BuildAND() string {
	fb.mu.Lock()
	defer fb.mu.Unlock()

	if len(fb.conditions) == 0 {
		return "(objectClass=*)"
	}
	if len(fb.conditions) == 1 {
		return fb.conditions[0]
	}
	return fmt.Sprintf("(&%s)", strings.Join(fb.conditions, ""))
}

// BuildOR combines all conditions with OR
func (fb *LDAPFilterBuilder) BuildOR() string {
	fb.mu.Lock()
	defer fb.mu.Unlock()

	if len(fb.conditions) == 0 {
		return "(objectClass=*)"
	}
	if len(fb.conditions) == 1 {
		return fb.conditions[0]
	}
	return fmt.Sprintf("(|%s)", strings.Join(fb.conditions, ""))
}

// SearchUsers performs a secure user search with audit logging
func (svc *LDAPSearchService) SearchUsers(ctx context.Context, criteria map[string]string, requestID string, clientIP string) ([]map[string]string, error) {
	// Audit log the search attempt
	svc.logger.Printf("[AUDIT] RequestID=%s ClientIP=%s Action=LDAP_SEARCH Criteria=%v",
		requestID, clientIP, sanitizeLogData(criteria))

	// Build filter safely
	fb := NewFilterBuilder()

	// Always require objectClass=user
	if err := fb.AddEquals("objectClass", "user"); err != nil {
		return nil, err
	}

	// Allowed searchable attributes (whitelist)
	allowedAttrs := map[string]bool{
		"sAMAccountName": true,
		"department":     true,
		"title":          true,
		"cn":             true,
		"mail":           true,
	}

	for attr, value := range criteria {
		if !allowedAttrs[attr] {
			svc.logger.Printf("[SECURITY] RequestID=%s Blocked disallowed attribute: %s", requestID, attr)
			continue
		}
		if value == "" {
			continue
		}
		if err := fb.AddEquals(attr, value); err != nil {
			return nil, fmt.Errorf("invalid search criteria: %w", err)
		}
	}

	filter := fb.BuildAND()

	// Get connection from pool with timeout
	var conn *ldap.Conn
	select {
	case conn = <-svc.pool:
		defer func() { svc.pool <- conn }()
	case <-ctx.Done():
		return nil, ctx.Err()
	case <-time.After(5 * time.Second):
		return nil, fmt.Errorf("connection pool timeout")
	}

	searchRequest := ldap.NewSearchRequest(
		svc.baseDN,
		ldap.ScopeWholeSubtree,
		ldap.NeverDerefAliases,
		svc.maxResults,
		int(svc.timeout.Seconds()),
		false,
		filter,
		[]string{"dn", "cn", "mail", "department", "title"}, // Restricted attributes
		nil,
	)

	result, err := conn.Search(searchRequest)
	if err != nil {
		svc.logger.Printf("[ERROR] RequestID=%s LDAP search failed: %v", requestID, err)
		return nil, fmt.Errorf("search failed")
	}

	// Transform results
	users := make([]map[string]string, 0, len(result.Entries))
	for _, entry := range result.Entries {
		user := map[string]string{
			"dn":         entry.DN,
			"cn":         entry.GetAttributeValue("cn"),
			"mail":       entry.GetAttributeValue("mail"),
			"department": entry.GetAttributeValue("department"),
			"title":      entry.GetAttributeValue("title"),
		}
		users = append(users, user)
	}

	svc.logger.Printf("[AUDIT] RequestID=%s Action=LDAP_SEARCH_COMPLETE ResultCount=%d",
		requestID, len(users))

	return users, nil
}

// sanitizeLogData removes sensitive info from log data
func sanitizeLogData(data map[string]string) map[string]string {
	sanitized := make(map[string]string)
	sensitiveFields := map[string]bool{"password": true, "userPassword": true}

	for k, v := range data {
		if sensitiveFields[k] {
			sanitized[k] = "[REDACTED]"
		} else if len(v) > 50 {
			sanitized[k] = v[:50] + "..."
		} else {
			sanitized[k] = v
		}
	}
	return sanitized
}
```

