<?php

class ProductionLdapService {
    private $ldapConn;
    private $config;
    private $logger;
    private $rateLimiter;

    // Whitelist of searchable attributes
    private const SEARCHABLE_ATTRIBUTES = [
        'department' => 'departmentNumber',
        'location' => 'l',
        'title' => 'title',
        'email' => 'mail',
        'name' => 'cn'
    ];

    // Whitelist of retrievable attributes
    private const RETRIEVABLE_ATTRIBUTES = [
        'cn', 'mail', 'telephoneNumber', 'department', 'title', 'l'
    ];

    public function __construct(array $config, $logger, $rateLimiter) {
        $this->config = $config;
        $this->logger = $logger;
        $this->rateLimiter = $rateLimiter;
    }

    /**
     * RFC 4515 compliant LDAP filter escaping
     */
    private function escapeLdapFilterValue($value) {
        $escapeChars = [
            '\\' => '\5c',
            '*'  => '\2a',
            '('  => '\28',
            ')'  => '\29',
            "\x00" => '\00',
            '/'  => '\2f'
        ];

        $escaped = str_replace(
            array_keys($escapeChars),
            array_values($escapeChars),
            $value
        );

        // Also escape high-bit characters
        $escaped = preg_replace_callback(
            '/[\x80-\xff]/',
            function($match) {
                return '\\' . bin2hex($match[0]);
            },
            $escaped
        );

        return $escaped;
    }

    /**
     * Escape DN component for safe binding
     */
    private function escapeDnComponent($value) {
        $escapeChars = [
            '\\' => '\\\\',
            ','  => '\\,',
            '+'  => '\\+',
            '"'  => '\\"',
            '<'  => '\\<',
            '>'  => '\\>',
            ';'  => '\\;',
            '='  => '\\=',
            '#'  => '\\#'
        ];

        return str_replace(
            array_keys($escapeChars),
            array_values($escapeChars),
            $value
        );
    }

    /**
     * Validate search criteria against whitelist
     */
    private function validateSearchCriteria(array $criteria) {
        $errors = [];

        foreach ($criteria as $field => $value) {
            // Check field is in whitelist
            if (!isset(self::SEARCHABLE_ATTRIBUTES[$field])) {
                $errors[] = "Invalid search field: {$field}";
                continue;
            }

            // Validate value length and characters
            if (strlen($value) < 1 || strlen($value) > 100) {
                $errors[] = "Invalid value length for field: {$field}";
            }

            // Basic character validation (allow unicode letters, numbers, spaces)
            if (!preg_match('/^[\p{L}\p{N}\s._-]+$/u', $value)) {
                $errors[] = "Invalid characters in field: {$field}";
            }
        }

        return $errors;
    }

    /**
     * Build safe LDAP filter from validated criteria
     */
    private function buildSafeFilter(array $criteria) {
        $filterParts = [];

        foreach ($criteria as $field => $value) {
            $ldapAttribute = self::SEARCHABLE_ATTRIBUTES[$field];
            $escapedValue = $this->escapeLdapFilterValue($value);
            $filterParts[] = "({$ldapAttribute}={$escapedValue})";
        }

        // Combine with AND operator
        if (count($filterParts) === 1) {
            return $filterParts[0];
        }

        return '(&' . implode('', $filterParts) . ')';
    }

    /**
     * Connect and bind to LDAP server
     */
    private function connect() {
        $this->ldapConn = ldap_connect(
            $this->config['host'],
            $this->config['port']
        );

        if (!$this->ldapConn) {
            throw new \RuntimeException('LDAP connection failed');
        }

        ldap_set_option($this->ldapConn, LDAP_OPT_PROTOCOL_VERSION, 3);
        ldap_set_option($this->ldapConn, LDAP_OPT_REFERRALS, 0);
        ldap_set_option($this->ldapConn, LDAP_OPT_NETWORK_TIMEOUT, 5);
        ldap_set_option($this->ldapConn, LDAP_OPT_TIMELIMIT, 10);

        // Bind with service account
        $bindResult = @ldap_bind(
            $this->ldapConn,
            $this->config['bind_dn'],
            $this->config['bind_password']
        );

        if (!$bindResult) {
            $error = ldap_error($this->ldapConn);
            $this->logger->error("LDAP bind failed", ['error' => $error]);
            throw new \RuntimeException('LDAP authentication failed');
        }
    }

    /**
     * Search LDAP with multiple criteria - production safe
     */
    public function searchUsers(array $criteria, string $clientIp, string $requestId) {
        // Rate limiting check
        if (!$this->rateLimiter->check($clientIp, 'ldap_search', 20, 60)) {
            $this->logger->warning('Rate limit exceeded for LDAP search', [
                'client_ip' => $clientIp,
                'request_id' => $requestId
            ]);
            throw new \RuntimeException('Rate limit exceeded');
        }

        // Validate all criteria before any LDAP operation
        $errors = $this->validateSearchCriteria($criteria);
        if (!empty($errors)) {
            $this->logger->warning('Invalid LDAP search criteria', [
                'errors' => $errors,
                'client_ip' => $clientIp,
                'request_id' => $requestId
            ]);
            throw new \InvalidArgumentException(implode('; ', $errors));
        }

        // Log search attempt (sanitized)
        $this->logger->info('LDAP search initiated', [
            'fields' => array_keys($criteria),
            'client_ip' => $clientIp,
            'request_id' => $requestId
        ]);

        try {
            $this->connect();

            $filter = $this->buildSafeFilter($criteria);

            // Limit search scope and results
            $searchResult = @ldap_search(
                $this->ldapConn,
                $this->config['base_dn'],
                $filter,
                self::RETRIEVABLE_ATTRIBUTES,  // Only retrieve whitelisted attributes
                0,  // attrsonly
                100,  // sizelimit - prevent large result sets
                10   // timelimit
            );

            if (!$searchResult) {
                $error = ldap_error($this->ldapConn);
                $this->logger->error('LDAP search failed', [
                    'error' => $error,
                    'request_id' => $requestId
                ]);
                return [];
            }

            $entries = ldap_get_entries($this->ldapConn, $searchResult);

            // Sanitize output - remove sensitive attributes
            $results = $this->sanitizeResults($entries);

            $this->logger->info('LDAP search completed', [
                'result_count' => count($results),
                'request_id' => $requestId
            ]);

            return $results;

        } catch (\Exception $e) {
            $this->logger->error('LDAP operation error', [
                'message' => $e->getMessage(),
                'request_id' => $requestId
            ]);
            throw new \RuntimeException('Directory search failed');
        } finally {
            if ($this->ldapConn) {
                ldap_close($this->ldapConn);
            }
        }
    }

    /**
     * Sanitize LDAP results for safe output
     */
    private function sanitizeResults(array $entries) {
        $results = [];

        for ($i = 0; $i < $entries['count']; $i++) {
            $entry = $entries[$i];
            $user = [];

            foreach (self::RETRIEVABLE_ATTRIBUTES as $attr) {
                $attrLower = strtolower($attr);
                if (isset($entry[$attrLower])) {
                    // Get first value only, sanitize for output
                    $value = $entry[$attrLower][0] ?? '';
                    $user[$attr] = htmlspecialchars($value, ENT_QUOTES, 'UTF-8');
                }
            }

            if (!empty($user)) {
                $results[] = $user;
            }
        }

        return $results;
    }

    /**
     * Secure user authentication with proper binding
     */
    public function authenticateUser(string $username, string $password, string $clientIp) {
        // Rate limiting for authentication
        if (!$this->rateLimiter->check($clientIp, 'ldap_auth', 5, 300)) {
            $this->logger->warning('Authentication rate limit exceeded', [
                'client_ip' => $clientIp
            ]);
            sleep(2);  // Add delay to slow brute force
            return false;
        }

        // Strict username validation
        if (!preg_match('/^[a-zA-Z0-9._-]{3,50}$/', $username)) {
            $this->logger->warning('Invalid username format', [
                'client_ip' => $clientIp
            ]);
            return false;
        }

        // Password requirements
        if (strlen($password) < 8 || strlen($password) > 256) {
            return false;
        }

        try {
            $this->connect();

            // Find user DN with escaped username
            $safeUsername = $this->escapeLdapFilterValue($username);
            $filter = "(uid={$safeUsername})";

            $searchResult = @ldap_search(
                $this->ldapConn,
                $this->config['base_dn'],
                $filter,
                ['dn'],
                0,
                1,
                5
            );

            if (!$searchResult) {
                return false;
            }

            $entries = ldap_get_entries($this->ldapConn, $searchResult);

            if ($entries['count'] !== 1) {
                return false;
            }

            $userDn = $entries[0]['dn'];

            // Authenticate by rebinding as user
            $authResult = @ldap_bind($this->ldapConn, $userDn, $password);

            // Log result (without sensitive data)
            $this->logger->info('Authentication attempt', [
                'success' => $authResult,
                'username' => $safeUsername,
                'client_ip' => $clientIp
            ]);

            return $authResult;

        } catch (\Exception $e) {
            $this->logger->error('Authentication error', [
                'client_ip' => $clientIp
            ]);
            return false;
        } finally {
            if ($this->ldapConn) {
                ldap_close($this->ldapConn);
            }
        }
    }
}

