Building dynamic LDAP filters requires a structured approach similar to parameterized SQL queries. Here's a production-ready pattern with a secure filter builder:

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.DirectoryServices;
using System.DirectoryServices.AccountManagement;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.Logging;

namespace Enterprise.Directory.Services
{
    public enum LdapOperator
    {
        And,
        Or
    }

    public class LdapFilterBuilder
    {
        private readonly List<string> _conditions = new List<string>();
        private readonly LdapOperator _operator;

        public LdapFilterBuilder(LdapOperator op = LdapOperator.And)
        {
            _operator = op;
        }

        // SECURE: All values go through escaping
        public LdapFilterBuilder AddCondition(string attribute, string value)
        {
            if (!IsValidAttribute(attribute))
                throw new ArgumentException($"Invalid attribute: {attribute}");

            string escapedValue = EscapeLdapValue(value);
            _conditions.Add($"({attribute}={escapedValue})");
            return this;
        }

        public LdapFilterBuilder AddPresenceCondition(string attribute)
        {
            if (!IsValidAttribute(attribute))
                throw new ArgumentException($"Invalid attribute: {attribute}");

            _conditions.Add($"({attribute}=*)");
            return this;
        }

        public LdapFilterBuilder AddNotCondition(string attribute, string value)
        {
            if (!IsValidAttribute(attribute))
                throw new ArgumentException($"Invalid attribute: {attribute}");

            string escapedValue = EscapeLdapValue(value);
            _conditions.Add($"(!({attribute}={escapedValue}))");
            return this;
        }

        public string Build()
        {
            if (_conditions.Count == 0)
                throw new InvalidOperationException("No conditions specified");

            if (_conditions.Count == 1)
                return _conditions[0];

            string op = _operator == LdapOperator.And ? "&" : "|";
            return $"({op}{string.Join("", _conditions)})";
        }

        // RFC 4515 compliant escaping
        private static string EscapeLdapValue(string input)
        {
            if (string.IsNullOrEmpty(input))
                return string.Empty;

            StringBuilder sb = new StringBuilder(input.Length + 10);
            foreach (char c in input)
            {
                switch (c)
                {
                    case '\\': sb.Append("\\5c"); break;
                    case '*': sb.Append("\\2a"); break;
                    case '(': sb.Append("\\28"); break;
                    case ')': sb.Append("\\29"); break;
                    case '\0': sb.Append("\\00"); break;
                    case '/': sb.Append("\\2f"); break;
                    default:
                        if (c < 32 || c > 126)
                            sb.AppendFormat("\\{0:x2}", (int)c);
                        else
                            sb.Append(c);
                        break;
                }
            }
            return sb.ToString();
        }

        // WHITELIST: Only allowed LDAP attributes
        private static readonly HashSet<string> AllowedAttributes = new HashSet<string>(
            StringComparer.OrdinalIgnoreCase)
        {
            "cn", "sAMAccountName", "mail", "department", "title",
            "givenName", "sn", "displayName", "objectClass", "memberOf",
            "manager", "telephoneNumber", "userPrincipalName"
        };

        private static bool IsValidAttribute(string attr)
        {
            return !string.IsNullOrWhiteSpace(attr) && 
                   AllowedAttributes.Contains(attr) &&
                   Regex.IsMatch(attr, @"^[a-zA-Z][a-zA-Z0-9\-]*$");
        }
    }

    public class EnterpriseDirectoryService : IDisposable
    {
        private readonly string _ldapPath;
        private readonly ILogger<EnterpriseDirectoryService> _logger;
        private readonly DirectoryEntry _rootEntry;
        private const int MaxResultSize = 500;
        private const int QueryTimeout = 30;

        public EnterpriseDirectoryService(
            string ldapPath,
            ILogger<EnterpriseDirectoryService> logger)
        {
            _ldapPath = ldapPath ?? throw new ArgumentNullException(nameof(ldapPath));
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
            _rootEntry = new DirectoryEntry(_ldapPath);
        }

        public IEnumerable<DirectoryUserInfo> SearchUsers(LdapFilterBuilder filterBuilder)
        {
            string filter = filterBuilder.Build();

            // AUDIT: Log all directory queries
            _logger.LogInformation(
                "LDAP Query executed. Filter: {Filter}, Timestamp: {Time}",
                SanitizeForLog(filter),
                DateTime.UtcNow);

            var results = new List<DirectoryUserInfo>();

            try
            {
                using (var searcher = new DirectorySearcher(_rootEntry))
                {
                    searcher.Filter = filter;
                    searcher.SizeLimit = MaxResultSize;
                    searcher.ServerTimeLimit = TimeSpan.FromSeconds(QueryTimeout);
                    searcher.ClientTimeout = TimeSpan.FromSeconds(QueryTimeout + 5);

                    // MINIMIZE: Only load required attributes
                    searcher.PropertiesToLoad.AddRange(new[]
                    {
                        "cn", "mail", "department", "title", "displayName"
                    });

                    // SECURITY: Disable referral chasing to prevent
                    // queries escaping to untrusted directories
                    searcher.ReferralChasing = ReferralChasingOption.None;

                    using (SearchResultCollection searchResults = searcher.FindAll())
                    {
                        foreach (SearchResult result in searchResults)
                        {
                            results.Add(MapToUserInfo(result));
                        }
                    }
                }

                _logger.LogInformation(
                    "LDAP Query returned {Count} results", results.Count);
            }
            catch (DirectoryServicesCOMException ex)
            {
                _logger.LogError(ex,
                    "LDAP query failed. Error: {Error}",
                    ex.Message);
                throw new DirectoryQueryException(
                    "Directory search failed", ex);
            }

            return results;
        }

        public bool ValidateCredentials(
            string username,
            string password,
            out string failureReason)
        {
            failureReason = null;

            // INPUT VALIDATION
            if (string.IsNullOrWhiteSpace(username) ||
                !Regex.IsMatch(username, @"^[a-zA-Z0-9._\-]+$") ||
                username.Length > 64)
            {
                failureReason = "Invalid username format";
                _logger.LogWarning(
                    "Authentication attempt with invalid username format");
                return false;
            }

            if (string.IsNullOrEmpty(password) || password.Length > 128)
            {
                failureReason = "Invalid password";
                return false;
            }

            try
            {
                // SECURE: Use PrincipalContext for authentication
                // instead of raw LDAP bind
                using (var context = new PrincipalContext(
                    ContextType.Domain,
                    Environment.GetEnvironmentVariable("AD_DOMAIN")))
                {
                    bool isValid = context.ValidateCredentials(
                        username,
                        password,
                        ContextOptions.Negotiate);

                    _logger.LogInformation(
                        "Authentication attempt for user {User}: {Result}",
                        username,
                        isValid ? "Success" : "Failed");

                    if (!isValid)
                        failureReason = "Invalid credentials";

                    return isValid;
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex,
                    "Authentication error for user {User}", username);
                failureReason = "Authentication service unavailable";
                return false;
            }
        }

        private DirectoryUserInfo MapToUserInfo(SearchResult result)
        {
            return new DirectoryUserInfo
            {
                CommonName = GetProperty(result, "cn"),
                Email = GetProperty(result, "mail"),
                Department = GetProperty(result, "department"),
                Title = GetProperty(result, "title"),
                DisplayName = GetProperty(result, "displayName")
            };
        }

        private string GetProperty(SearchResult result, string propertyName)
        {
            if (result.Properties.Contains(propertyName) &&
                result.Properties[propertyName].Count > 0)
            {
                return result.Properties[propertyName][0]?.ToString();
            }
            return null;
        }

        private string SanitizeForLog(string input)
        {
            if (input == null) return "[null]";
            return Regex.Replace(input, @"[\r\n]", " ").Substring(
                0, Math.Min(input.Length, 200));
        }

        public void Dispose()
        {
            _rootEntry?.Dispose();
        }
    }

    public class DirectoryUserInfo
    {
        public string CommonName { get; set; }
        public string Email { get; set; }
        public string Department { get; set; }
        public string Title { get; set; }
        public string DisplayName { get; set; }
    }

    public class DirectoryQueryException : Exception
    {
        public DirectoryQueryException(string message, Exception inner)
            : base(message, inner) { }
    }
}
