var filter = new LdapFilterBuilder(LdapOperator.And)
    .AddCondition("objectClass", "user")
    .AddCondition("department", userInput)  // Automatically escaped
    .AddCondition("title", "Manager")
    .Build();
// Result: (&(objectClass=user)(department=\2a\28injected\29)(title=Manager))
