**Additional Protections**:
- **Use PrincipalContext for Authentication**: Safer than raw LDAP binds, handles Kerberos/NTLM properly
- **Comprehensive Audit Logging**: All queries logged with sanitized filters for forensic analysis
- **Environment-Based Configuration**: Domain names from environment variables, not hardcoded
- **Secure Error Handling**: Internal errors don't leak directory structure to clients
- **Attribute Minimization**: PropertiesToLoad restricts returned data to prevent accidental exposure of sensitive attributes like password hashes or security descriptors

For production systems with dynamic multi-column sorting, you need a centralized, maintainable approach with struct tags, reflection-based validation, and defense in depth.

**PRODUCTION PATTERN**:

```go
package main

import (
    "context"
    "database/sql"
    "fmt"
    "log/slog"
    "net/http"
    "os"
    "reflect"
    "regexp"
    "strings"
    "time"

    "github.com/gin-gonic/gin"
    _ "github.com/lib/pq"
)

// SortConfig defines sorting metadata via struct tags
type Product struct {
    ID        int       `json:"id" db:"id" sortable:"true"`
    Name      string    `json:"name" db:"name" sortable:"true"`
    Price     float64   `json:"price" db:"price" sortable:"true"`
    SKU       string    `json:"sku" db:"sku" sortable:"true"`
    CreatedAt time.Time `json:"created_at" db:"created_at" sortable:"true"`
    Secret    string    `json:"-" db:"internal_notes" sortable:"false"` // Not sortable
}

// SortableRegistry builds allowlist from struct tags at startup
type SortableRegistry struct {
    columns map[string]map[string]string // entity -> (alias -> db_column)
    logger  *slog.Logger
}

func NewSortableRegistry(logger *slog.Logger) *SortableRegistry {
    return &SortableRegistry{
        columns: make(map[string]map[string]string),
        logger:  logger,
    }
}

// RegisterEntity scans struct tags to build allowlist
func (r *SortableRegistry) RegisterEntity(name string, entity interface{}) {
    t := reflect.TypeOf(entity)
    if t.Kind() == reflect.Ptr {
        t = t.Elem()
    }

    r.columns[name] = make(map[string]string)

    for i := 0; i < t.NumField(); i++ {
        field := t.Field(i)
        if field.Tag.Get("sortable") == "true" {
            jsonName := field.Tag.Get("json")
            dbName := field.Tag.Get("db")
            if jsonName != "" && jsonName != "-" && dbName != "" {
                r.columns[name][jsonName] = dbName
            }
        }
    }

    r.logger.Info("Registered sortable entity",
        "entity", name,
        "columns", r.columns[name])
}

// ValidateSort checks if sort parameters are safe
func (r *SortableRegistry) ValidateSort(entity, column string) (string, bool) {
    if entityCols, ok := r.columns[entity]; ok {
        if dbCol, valid := entityCols[strings.ToLower(column)]; valid {
            return dbCol, true
        }
    }
    return "", false
}

// SortParams represents validated sort configuration
type SortParams struct {
    Columns []string
    Orders  []string
}

// QueryBuilder builds safe ORDER BY clauses
type QueryBuilder struct {
    registry      *SortableRegistry
    maxSortCols   int
    allowedOrders map[string]string
    logger        *slog.Logger
}

func NewQueryBuilder(registry *SortableRegistry, logger *slog.Logger) *QueryBuilder {
    return &QueryBuilder{
        registry:    registry,
        maxSortCols: 3, // Limit complexity
        allowedOrders: map[string]string{
            "asc":  "ASC",
            "desc": "DESC",
        },
        logger: logger,
    }
}

// ParseSortParams safely parses and validates sort input
func (qb *QueryBuilder) ParseSortParams(entity, sortParam, orderParam string) (*SortParams, error) {
    if sortParam == "" {
        return &SortParams{
            Columns: []string{"id"},
            Orders:  []string{"ASC"},
        }, nil
    }

    // Basic input sanitization - only alphanumeric and commas
    validPattern := regexp.MustCompile(`^[a-zA-Z0-9_,]+$`)
    if !validPattern.MatchString(sortParam) || !validPattern.MatchString(orderParam) {
        return nil, fmt.Errorf("invalid characters in sort parameters")
    }

    columns := strings.Split(sortParam, ",")
    orders := strings.Split(orderParam, ",")

    // Limit number of sort columns to prevent DoS
    if len(columns) > qb.maxSortCols {
        return nil, fmt.Errorf("maximum %d sort columns allowed", qb.maxSortCols)
    }

    // Pad orders if fewer than columns
    for len(orders) < len(columns) {
        orders = append(orders, "asc")
    }

    params := &SortParams{
        Columns: make([]string, 0, len(columns)),
        Orders:  make([]string, 0, len(columns)),
    }

    for i, col := range columns {
        col = strings.TrimSpace(strings.ToLower(col))

        dbCol, valid := qb.registry.ValidateSort(entity, col)
        if !valid {
            qb.logger.Warn("Invalid sort column rejected",
                "entity", entity,
                "column", col)
            return nil, fmt.Errorf("invalid sort column: %s", col)
        }

        order := strings.TrimSpace(strings.ToLower(orders[i]))
        dbOrder, validOrder := qb.allowedOrders[order]
        if !validOrder {
            return nil, fmt.Errorf("invalid sort order: %s", order)
        }

        params.Columns = append(params.Columns, dbCol)
        params.Orders = append(params.Orders, dbOrder)
    }

    return params, nil
}

// BuildOrderByClause constructs safe ORDER BY SQL
func (qb *QueryBuilder) BuildOrderByClause(params *SortParams) string {
    if params == nil || len(params.Columns) == 0 {
        return "ORDER BY id ASC"
    }

    parts := make([]string, len(params.Columns))
    for i := range params.Columns {
        // Only allowlisted values reach here
        parts[i] = fmt.Sprintf("%s %s", params.Columns[i], params.Orders[i])
    }

    return "ORDER BY " + strings.Join(parts, ", ")
}

// ProductService handles product queries
type ProductService struct {
    db           *sql.DB
    queryBuilder *QueryBuilder
    logger       *slog.Logger
}

func (s *ProductService) GetProducts(ctx context.Context, sortParam, orderParam string, limit, offset int) ([]Product, error) {
    // Validate pagination limits
    if limit <= 0 || limit > 100 {
        limit = 20
    }
    if offset < 0 {
        offset = 0
    }

    // Parse and validate sort params
    sortParams, err := s.queryBuilder.ParseSortParams("product", sortParam, orderParam)
    if err != nil {
        s.logger.Warn("Invalid sort parameters",
            "sort", sortParam,
            "order", orderParam,
            "error", err)
        return nil, err
    }

    orderByClause := s.queryBuilder.BuildOrderByClause(sortParams)

    // Build query with validated ORDER BY and parameterized LIMIT/OFFSET
    query := fmt.Sprintf(
        "SELECT id, name, price, sku, created_at FROM products %s LIMIT $1 OFFSET $2",
        orderByClause,
    )

    s.logger.Debug("Executing query",
        "query", query,
        "limit", limit,
        "offset", offset)

    // Use context with timeout
    queryCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
    defer cancel()

    rows, err := s.db.QueryContext(queryCtx, query, limit, offset)
    if err != nil {
        s.logger.Error("Database query failed", "error", err)
        return nil, fmt.Errorf("database error")
    }
    defer rows.Close()

    products := make([]Product, 0)
    for rows.Next() {
        var p Product
        if err := rows.Scan(&p.ID, &p.Name, &p.Price, &p.SKU, &p.CreatedAt); err != nil {
            s.logger.Error("Row scan failed", "error", err)
            continue
        }
        products = append(products, p)
    }

    if err := rows.Err(); err != nil {
        s.logger.Error("Row iteration error", "error", err)
        return nil, fmt.Errorf("database error")
    }

    return products, nil
}

// Handler with audit logging
func (s *ProductService) HandleGetProducts(c *gin.Context) {
    startTime := time.Now()
    requestID := c.GetHeader("X-Request-ID")

    sortParam := c.DefaultQuery("sort", "id")
    orderParam := c.DefaultQuery("order", "asc")

    products, err := s.GetProducts(c.Request.Context(), sortParam, orderParam, 20, 0)
    if err != nil {
        s.logger.Warn("Request failed",
            "request_id", requestID,
            "client_ip", c.ClientIP(),
            "sort", sortParam,
            "order", orderParam,
            "error", err,
            "duration_ms", time.Since(startTime).Milliseconds())

        c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid parameters"})
        return
    }

    s.logger.Info("Products retrieved",
        "request_id", requestID,
        "client_ip", c.ClientIP(),
        "result_count", len(products),
        "duration_ms", time.Since(startTime).Milliseconds())

    c.JSON(http.StatusOK, products)
}

func main() {
    logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
        Level: slog.LevelInfo,
    }))

    // Initialize registry and register entities
    registry := NewSortableRegistry(logger)
    registry.RegisterEntity("product", Product{})

    queryBuilder := NewQueryBuilder(registry, logger)

    // Database connection would be initialized here
    // db, _ := sql.Open("postgres", os.Getenv("DATABASE_URL"))

    service := &ProductService{
        // db:           db,
        queryBuilder: queryBuilder,
        logger:       logger,
    }

    r := gin.New()
    r.Use(gin.Recovery())

    r.GET("/api/products", service.HandleGetProducts)

    r.Run(":8080")
}
```

**Defense in Depth Layers**:

1. **Struct Tag-Based Allowlist** - Columns are registered at startup from struct tags, ensuring only explicitly marked fields are sortable:
```go
type Product struct {
    Price  float64 `json:"price" db:"price" sortable:"true"`
    Secret string  `json:"-" db:"internal_notes" sortable:"false"`
}
```

2. **Input Sanitization** - Regex validation rejects special characters before allowlist check:
```go
validPattern := regexp.MustCompile(`^[a-zA-Z0-9_,]+$`)
if !validPattern.MatchString(sortParam) {
    return nil, fmt.Errorf("invalid characters")
}
```

3. **Complexity Limits** - Maximum sort columns prevent query complexity DoS:
```go
if len(columns) > qb.maxSortCols {
    return nil, fmt.Errorf("maximum %d sort columns allowed", qb.maxSortCols)
}
```

4. **Query Timeout** - Context-based timeout prevents long-running attack queries:
```go
queryCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
defer cancel()
rows, err := s.db.QueryContext(queryCtx, query, limit, offset)
```

**Additional Protections**:
- **Centralized validation**: All sort logic goes through QueryBuilder, making audits easier
- **Structured logging**: All requests logged with client IP, parameters, and timing for forensics
- **Generic error responses**: Internal errors don't leak database structure to attackers
- **Pagination limits**: Hardcoded maximum prevents data exfiltration via large result sets
- **Request ID tracking**: Correlate logs across services for incident investigation
- **Automatic registration**: Adding sortable:true to new fields automatically enables sorting without code changes
